1	// Edge function: get-listing-detail (US-039)
2	//
3	// Contract:
4	//   POST { listing_id: string }
5	//     → 200 {
6	//         listing:          <row from public.listings>,
7	//         conditions:       <rows from listing_conditions, both kinds>,
8	//         sample_videos:    <rows from sample_videos>,
9	//         eligibility: {
10	//           eligible:                boolean,
11	//           failed_conditions:       Array<{metric, platform, required, actual}>,
12	//           has_active_application:  boolean,
13	//         }
14	//       }
15	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
16	//     → 401 { error: 'UNAUTHORIZED' }
17	//     → 403 { error: 'FORBIDDEN' }       // non-creator role
18	//     → 404 { error: 'LISTING_NOT_FOUND' } // also covers draft/archived listings
19	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
20	//
21	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Verifies via
22	//       _shared/jwt.ts and asserts role='creator'. Deployed with
23	//       verify_jwt=false at the gateway because the gateway only knows
24	//       about Supabase's own JWT secret — the handler enforces auth.
25	//
26	// Response shape — primary reference is docs/tech-architecture.md §5.4
27	// (spec is authoritative per the Ralph iteration rules). Two deltas vs
28	// the US-039 story AC, both driven by §5.4:
29	//   1. `conditions` is a single array — the client splits by `kind`.
30	//      The story's `pre_conditions` / `post_conditions` split contradicts
31	//      §5.4's single `conditions: ListingCondition[]` field.
32	//   2. `eligibility.failed_conditions` is `Array<{metric, required, actual}>`
33	//      — the story's `reasons: string[]` contradicts §5.4. We also keep
34	//      `platform` as an additive disambiguator because `min_followers`
35	//      would otherwise be ambiguous across TikTok/Instagram; §5.4 is
36	//      under-specified on the item shape and an additive field is not
37	//      a structural departure.
38	//
39	// Eligibility — only PRE conditions gate apply-time eligibility per
40	// docs/tech-architecture.md §6.3 ("Pre-conditions: evaluated on all
41	// posts; post-conditions: evaluated on submissions"). POST conditions
42	// are returned in `conditions` for the UI to display but do not
43	// contribute to `eligible` / `failed_conditions`.
44	//
45	// Fail-closed on missing metrics (§3d): when the creator hasn't been
46	// scraped yet (or a specific platform field is NULL), the PRE condition
47	// keyed on that field fails — the spec calls this out explicitly for
48	// Instagram `min_avg_views_last_n` ("Listings that require … treat null
49	// as ineligible (fail-closed).") and we apply the same rule uniformly.
50	// The same rule extends to pre-condition rows with an unknown operator
51	// or unreadable metric: treat as failed rather than silently passing,
52	// so a future mis-migrated row can't flip a listing to eligible by
53	// accident.
54	//
55	// Visibility — a creator lookup against a `draft` or `archived` listing
56	// collapses to 404. Draft is never public; archived is terminal and no
57	// application path can succeed against it, so leaking its existence
58	// would only produce a dead-end detail view. `paused` and `closed` still
59	// return 200 so a creator with an existing application can view the
60	// detail; the Apply CTA in US-040 gates off `listing.status`.
61	
62	import { createClient } from "npm:@supabase/supabase-js@2";
63	import { verifyJwt } from "../_shared/jwt.ts";
64	import { corsHeaders } from "../_shared/cors.ts";
65	
66	const UUID_RE =
67	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
68	
69	type Platform = "tiktok" | "instagram";
70	type ConditionKind = "pre" | "post";
71	
72	interface ConditionRow {
73	  id: string;
74	  listing_version_id: string;
75	  kind: ConditionKind;
76	  metric: string;
77	  platform: Platform | null;
78	  operator: string;
79	  numeric_threshold: string | number | null;
80	  text_threshold: string | null;
81	  bool_threshold: boolean | null;
82	  created_at: string;
83	}
84	
85	interface CreatorProfileRow {
86	  tiktok_follower_count: number | null;
87	  tiktok_avg_views_last_10: number | null;
88	  tiktok_total_likes: number | null;
89	  tiktok_video_count: number | null;
90	  tiktok_is_verified: boolean | null;
91	  instagram_follower_count: number | null;
92	  instagram_avg_views_last_10: number | null;
93	  instagram_media_count: number | null;
94	}
95	
96	interface FailedCondition {
97	  metric: string;
98	  platform: Platform | null;
99	  required: number | boolean;
100	  actual: number | boolean | null;
101	}
102	
103	interface DetailRequest {
104	  listing_id?: unknown;
105	}
106	
107	function jsonResponse(status: number, body: unknown): Response {
108	  return new Response(JSON.stringify(body), {
109	    status,
110	    headers: { ...corsHeaders, "Content-Type": "application/json" },
111	  });
112	}
113	
114	function bearerToken(req: Request): string | null {
115	  const raw = req.headers.get("Authorization") ??
116	    req.headers.get("authorization");
117	  if (!raw) return null;
118	  const m = raw.match(/^Bearer\s+(.+)$/i);
119	  return m ? m[1].trim() : null;
120	}
121	
122	// Evaluate a single pre-condition against the creator's denormalized
123	// metrics. Returns `null` on pass, or the failed-condition detail on fail.
124	// Missing data (null actual for a numeric threshold) fails closed per §3d.
125	function evaluatePreCondition(
126	  condition: ConditionRow,
127	  metrics: CreatorProfileRow,
128	): FailedCondition | null {
129	  const { metric, platform, operator } = condition;
130	  if (operator === "gte") {
131	    const required = Number(condition.numeric_threshold);
132	    if (!Number.isFinite(required)) return null; // malformed row — skip, not fail
133	    const actual = readNumericMetric(metrics, platform, metric);
134	    if (actual === null || actual < required) {
135	      return { metric, platform, required, actual };
136	    }
137	    return null;
138	  }
139	  if (operator === "bool") {
140	    const required = condition.bool_threshold === true;
141	    const actual = readBoolMetric(metrics, platform, metric);
142	    if (actual !== required) {
143	      return { metric, platform, required, actual };
144	    }
145	    return null;
146	  }
147	  // Unknown operator on a PRE row — fail-closed per §3d. `eq`/`contains`/`lte`
148	  // are reserved for post-conditions today (e.g. post_must_mention uses
149	  // 'contains'), so this branch should be unreachable; if a future migration
150	  // misplaces an operator, we'd rather block an apply than silently allow it.
151	  console.warn("pre-condition with unknown operator treated as failed", {
152	    condition_id: condition.id,
153	    operator,
154	    metric,
155	    platform,
156	  });
157	  const parsed = Number(condition.numeric_threshold);
158	  return {
159	    metric,
160	    platform,
161	    required: Number.isFinite(parsed) ? parsed : 0,
162	    actual: null,
163	  };
164	}
165	
166	function readNumericMetric(
167	  metrics: CreatorProfileRow,
168	  platform: Platform | null,
169	  metric: string,
170	): number | null {
171	  if (platform === "tiktok") {
172	    switch (metric) {
173	      case "min_followers":
174	        return metrics.tiktok_follower_count;
175	      case "min_avg_views_last_n":
176	        return metrics.tiktok_avg_views_last_10;
177	      case "min_total_likes":
178	        return metrics.tiktok_total_likes;
179	      case "min_videos_posted":
180	        return metrics.tiktok_video_count;
181	      default:
182	        return null;
183	    }
184	  }
185	  if (platform === "instagram") {
186	    switch (metric) {
187	      case "min_followers":
188	        return metrics.instagram_follower_count;
189	      case "min_avg_views_last_n":
190	        return metrics.instagram_avg_views_last_10;
191	      case "min_videos_posted":
192	        return metrics.instagram_media_count;
193	      default:
194	        return null;
195	    }
196	  }
197	  return null;
198	}
199	
200	function readBoolMetric(
201	  metrics: CreatorProfileRow,
202	  platform: Platform | null,
203	  metric: string,
204	): boolean | null {
205	  if (platform === "tiktok" && metric === "verified_only") {
206	    return metrics.tiktok_is_verified;
207	  }
208	  return null;
209	}
210	
211	Deno.serve(async (req) => {
212	  if (req.method === "OPTIONS") {
213	    return new Response(null, { status: 204, headers: corsHeaders });
214	  }
215	  if (req.method !== "POST") {
216	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
217	  }
218	
219	  const token = bearerToken(req);
220	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
221	
222	  let claims;
223	  try {
224	    claims = await verifyJwt(token);
225	  } catch {
226	    return jsonResponse(401, { error: "UNAUTHORIZED" });
227	  }
228	  if (claims.role !== "creator") {
229	    return jsonResponse(403, { error: "FORBIDDEN" });
230	  }
231	
232	  let body: DetailRequest;
233	  try {
234	    body = await req.json();
235	  } catch {
236	    return jsonResponse(400, { error: "INVALID_JSON" });
237	  }
238	
239	  const listingId =
240	    typeof body.listing_id === "string" && UUID_RE.test(body.listing_id)
241	      ? body.listing_id
242	      : null;
243	  if (!listingId) {
244	    return jsonResponse(400, { error: "INVALID_REQUEST" });
245	  }
246	
247	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
248	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
249	  if (!supabaseUrl || !serviceRoleKey) {
250	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
251	  }
252	
253	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
254	    auth: { persistSession: false, autoRefreshToken: false },
255	  });
256	
257	  const { data: listing, error: listingError } = await supabase
258	    .from("listings")
259	    .select("*")
260	    .eq("id", listingId)
261	    .maybeSingle();
262	
263	  if (listingError) {
264	    console.error("listings lookup failed", listingError);
265	    return jsonResponse(500, { error: "DB_ERROR" });
266	  }
267	  // Drafts are never visible to non-owners; archived is terminal and no
268	  // apply path can succeed against it. Both collapse to 404 so id
269	  // existence doesn't leak and the UI never lands on a dead-end detail
270	  // view. `paused`/`closed` stay accessible so a creator with an existing
271	  // application can still open the detail; the Apply CTA in US-040 gates
272	  // off `listing.status`.
273	  if (!listing || listing.status === "draft" || listing.status === "archived") {
274	    return jsonResponse(404, { error: "LISTING_NOT_FOUND" });
275	  }
276	
277	  const versionId = listing.current_version_id as string | null;
278	  if (!versionId) {
279	    // Data-integrity guard — publish (US-010 POST /listings) is what sets
280	    // `current_version_id` on the first version; the bump trigger updates
281	    // it on subsequent edits. A non-draft/non-archived listing without a
282	    // current_version_id is a persistence bug, not a normal state — fail
283	    // with DB_ERROR rather than return an inconsistent response.
284	    console.error("listing missing current_version_id", listing.id);
285	    return jsonResponse(500, { error: "DB_ERROR" });
286	  }
287	
288	  const [conditionsRes, videosRes, profileRes, appsRes] = await Promise.all([
289	    supabase
290	      .from("listing_conditions")
291	      .select("*")
292	      .eq("listing_version_id", versionId)
293	      .order("kind", { ascending: true })
294	      .order("metric", { ascending: true }),
295	    supabase
296	      .from("sample_videos")
297	      .select("*")
298	      .eq("listing_version_id", versionId)
299	      .order("sort_order", { ascending: true }),
300	    supabase
301	      .from("creator_profiles")
302	      .select(
303	        "tiktok_follower_count,tiktok_avg_views_last_10,tiktok_total_likes," +
304	          "tiktok_video_count,tiktok_is_verified,instagram_follower_count," +
305	          "instagram_avg_views_last_10,instagram_media_count",
306	      )
307	      .eq("user_id", claims.sub)
308	      .maybeSingle(),
309	    supabase
310	      .from("applications")
311	      .select("id")
312	      .eq("listing_id", listingId)
313	      .eq("creator_id", claims.sub)
314	      .in("status", ["pending", "approved"])
315	      .limit(1),
316	  ]);
317	
318	  if (conditionsRes.error) {
319	    console.error("listing_conditions lookup failed", conditionsRes.error);
320	    return jsonResponse(500, { error: "DB_ERROR" });
321	  }
322	  if (videosRes.error) {
323	    console.error("sample_videos lookup failed", videosRes.error);
324	    return jsonResponse(500, { error: "DB_ERROR" });
325	  }
326	  if (profileRes.error) {
327	    console.error("creator_profiles lookup failed", profileRes.error);
328	    return jsonResponse(500, { error: "DB_ERROR" });
329	  }
330	  if (appsRes.error) {
331	    console.error("applications lookup failed", appsRes.error);
332	    return jsonResponse(500, { error: "DB_ERROR" });
333	  }
334	
335	  const conditions = (conditionsRes.data ?? []) as ConditionRow[];
336	
337	  // Creator profile is created by the signup flow (US-014) so every
338	  // creator JWT should have one, but treat a missing row as fully-null
339	  // metrics — fail-closed on every numeric threshold.
340	  const metrics: CreatorProfileRow = profileRes.data ?? {
341	    tiktok_follower_count: null,
342	    tiktok_avg_views_last_10: null,
343	    tiktok_total_likes: null,
344	    tiktok_video_count: null,
345	    tiktok_is_verified: null,
346	    instagram_follower_count: null,
347	    instagram_avg_views_last_10: null,
348	    instagram_media_count: null,
349	  };
350	
351	  const failed: FailedCondition[] = [];
352	  for (const c of conditions) {
353	    if (c.kind !== "pre") continue;
354	    const miss = evaluatePreCondition(c, metrics);
355	    if (miss) failed.push(miss);
356	  }
357	  const eligible = failed.length === 0;
358	  const hasActiveApplication = (appsRes.data ?? []).length > 0;
359	
360	  return jsonResponse(200, {
361	    listing,
362	    conditions,
363	    sample_videos: videosRes.data ?? [],
364	    eligibility: {
365	      eligible,
366	      failed_conditions: failed,
367	      has_active_application: hasActiveApplication,
368	    },
369	  });
370	});
371

    )
  );

-- ---------------- applications ----------------
drop policy if exists applications_creator_rw on public.applications;
create policy applications_creator_rw on public.applications
  for all
  using (creator_id = public.current_user_id())
  with check (creator_id = public.current_user_id());

drop policy if exists applications_lister_read on public.applications;
create policy applications_lister_read on public.applications for select
  using (
    exists (
      select 1 from public.listings l
      where l.id = public.applications.listing_id
        and l.lister_id = public.current_user_id()
    )
  );

drop policy if exists applications_lister_decide on public.applications;
create policy applications_lister_decide on public.applications for update
  using (
    exists (
      select 1 from public.listings l
      where l.id = public.applications.listing_id
        and l.lister_id = public.current_user_id()
    )
  )
  with check (
    exists (
      select 1 from public.listings l
      where l.id = public.applications.listing_id
        and l.lister_id = public.current_user_id()
    )
  );

1	// Edge function: auth-signup-lister (US-014)
2	//
3	// Contract:
4	//   POST { username: string, email: string, org_name: string, website_url?: string }
5	//     → 200 { token: string, user_id: string, role: 'lister' }
6	//     → 400 { error: 'INVALID_REQUEST' | 'INVALID_JSON' }
7	//     → 409 { error: 'USERNAME_TAKEN' | 'EMAIL_TAKEN' }
8	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'JWT_ERROR' }
9	//
10	// Auth: none. This is how a lister obtains their first JWT, so the endpoint
11	// is verify_jwt=false at the gateway. The handler itself mints the token via
12	// _shared/jwt.ts (HS256, MARKETIFY_JWT_SECRET).
13	//
14	// Atomicity: the users + lister_profiles inserts run inside a single
15	// Postgres transaction via the public.auth_signup_lister RPC (us_014
16	// migration). A failure on the second insert rolls back the first.
17	//
18	// Rate limit: not implemented yet. Spec §5.1 requires per-IP throttling via
19	// a signup_attempts table, which does not exist as of US-014. Tracked in
20	// progress.txt Codebase Patterns as a future-story item.
21	
22	import { createClient } from "npm:@supabase/supabase-js@2";
23	import { signJwt } from "../_shared/jwt.ts";
24	import { corsHeaders } from "../_shared/cors.ts";
25	
26	interface SignupRequest {
27	  username?: unknown;
28	  email?: unknown;
29	  org_name?: unknown;
30	  website_url?: unknown;
31	}
32	
33	function jsonResponse(status: number, body: unknown): Response {
34	  return new Response(JSON.stringify(body), {
35	    status,
36	    headers: { ...corsHeaders, "Content-Type": "application/json" },
37	  });
38	}
39	
40	function isNonEmptyString(value: unknown): value is string {
41	  return typeof value === "string" && value.trim().length > 0;
42	}
43	
44	Deno.serve(async (req) => {
45	  if (req.method === "OPTIONS") {
46	    return new Response(null, { status: 204, headers: corsHeaders });
47	  }
48	  if (req.method !== "POST") {
49	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
50	  }
51	
52	  let body: SignupRequest;
53	  try {
54	    body = await req.json();
55	  } catch {
56	    return jsonResponse(400, { error: "INVALID_JSON" });
57	  }
58	
59	  const username = isNonEmptyString(body.username) ? body.username.trim() : null;
60	  const email = isNonEmptyString(body.email) ? body.email.trim() : null;
61	  const orgName = isNonEmptyString(body.org_name) ? body.org_name.trim() : null;
62	  const websiteUrl = isNonEmptyString(body.website_url)
63	    ? body.website_url.trim()
64	    : null;
65	
66	  if (!username || !email || !orgName) {
67	    return jsonResponse(400, { error: "INVALID_REQUEST" });
68	  }
69	
70	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
71	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
72	  if (!supabaseUrl || !serviceRoleKey) {
73	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
74	  }
75	
76	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
77	    auth: { persistSession: false, autoRefreshToken: false },
78	  });
79	
80	  const { data, error } = await supabase.rpc("auth_signup_lister", {
81	    p_username: username,
82	    p_email: email,
83	    p_org_name: orgName,
84	    p_website_url: websiteUrl,
85	  });
86	
87	  if (error) {
88	    console.error("auth_signup_lister rpc error", error);
89	    return jsonResponse(500, { error: "DB_ERROR" });
90	  }
91	
92	  const result = data as { user_id?: string; error?: string } | null;
93	  if (result?.error === "USERNAME_TAKEN") {
94	    return jsonResponse(409, { error: "USERNAME_TAKEN" });
95	  }
96	  if (result?.error === "EMAIL_TAKEN") {
97	    return jsonResponse(409, { error: "EMAIL_TAKEN" });
98	  }
99	  if (!result?.user_id) {
100	    console.error("auth_signup_lister returned unexpected shape", result);
101	    return jsonResponse(500, { error: "DB_ERROR" });
102	  }
103	
104	  const userId = result.user_id;
105	  const sessionId = crypto.randomUUID();
106	  let token: string;
107	  try {
108	    token = await signJwt({
109	      sub: userId,
110	      role: "lister",
111	      session_id: sessionId,
112	    });
113	  } catch (err) {
114	    console.error("signJwt failed", err);
115	    return jsonResponse(500, { error: "JWT_ERROR" });
116	  }
117	
118	  return jsonResponse(200, { token, user_id: userId, role: "lister" });
119	});
120

1	// Edge function: auth-signup-creator (US-019 + US-020)
2	//
3	// Contract:
4	//   POST { username: string, tiktok_handle?: string, instagram_handle?: string }
5	//     → 200 {
6	//         token: string,
7	//         user_id: string,
8	//         role: 'creator',
9	//         metrics_status: { tiktok?: Status, ig_details?: Status, ig_posts?: Status },
10	//       }
11	//       where Status is 'fresh' | 'refreshing' | 'failed'.
12	//     → 400 { error: 'INVALID_REQUEST' | 'INVALID_JSON' }
13	//     → 422 { error: 'HANDLE_REQUIRED' }
14	//     → 409 { error: 'USERNAME_TAKEN' | 'HANDLE_TAKEN' }
15	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'JWT_ERROR' }
16	//
17	// Auth: none. This is how a creator obtains their first JWT, so the
18	// endpoint is verify_jwt=false at the gateway. The handler itself mints
19	// the token via _shared/jwt.ts (HS256, MARKETIFY_JWT_SECRET).
20	//
21	// Atomicity: the users + creator_profiles + social_links inserts run
22	// inside a single Postgres transaction via the public.auth_signup_creator
23	// RPC (us_019 migration). A failure on any insert rolls back the flow.
24	// Apify dispatch happens AFTER the RPC commits — per spec §5.1, a
25	// dispatch failure does NOT roll back the account (the user gets their
26	// JWT, metrics_status carries the per-platform outcome so the client can
27	// decide whether to retry later or surface a 'refreshing' placeholder).
28	//
29	// Handle normalization: leading '@' is stripped and whitespace trimmed
30	// before the RPC call. Handles are compared case-insensitively (citext),
31	// matching social_links.handle's column type.
32	//
33	// Apify dispatch (US-020): once the RPC commits, we look up the
34	// freshly-inserted social_links rows, then kick one or more Apify runs in
35	// parallel via Promise.allSettled — tiktok_profile for TikTok handles;
36	// ig_details and ig_posts for Instagram handles. Each run is registered
37	// with a per-run webhook pointing back at /functions/v1/apify-webhook so
38	// the receiver can persist the metric_snapshots row when Apify finishes.
39	// The wait window is APIFY_WAIT_SECS (60s); runs that come back
40	// SUCCEEDED within the window are reported as 'fresh' (the webhook will
41	// also arrive and be deduped via the unique index on run_id), otherwise
42	// 'refreshing' and the client polls. A thrown dispatch is 'failed'.
43	//
44	// Pre-refreshing rows: the spec calls for pre-creating metric_snapshots
45	// rows in status='refreshing' before the scrape so the client has
46	// something to read. That's deferred — the existing US-016..US-018 RPCs
47	// INSERT on webhook arrival via ON CONFLICT DO NOTHING, so the row
48	// appears only once Apify finishes. Tracked as a spec gap in progress.txt.
49	//
50	// Rate limit: not implemented yet. Spec §5.1 requires per-IP throttling
51	// via a signup_attempts table (does not yet exist). Same status as the
52	// sibling auth-signup-lister — tracked in progress.txt Codebase Patterns.
53	
